// src/components/CreateDestination.jsx
import { useRef, useState } from 'react';
import { PlaceAutocompleteElement } from '@googlemaps/places-widget';
import { GoogleMap, MarkerF } from '@react-google-maps/api';
import mapStyles from '../styles/mapStyles';
import '../styles/CreateDestination.css';

const defaultCenter = { lat: 48.8566, lng: 2.3522 }; // Paris par défaut

export default function CreateDestination({ onCreate }) {
    const [location, setLocation] = useState(defaultCenter);
    const [name, setName] = useState('');
    const [image, setImage] = useState('');
    const mapRef = useRef(null);

    const handlePlaceSelect = (e) => {
        const place = e.detail.place;
        if (place.geometry && place.geometry.location) {
            const lat = place.geometry.location.lat();
            const lng = place.geometry.location.lng();
            setLocation({ lat, lng });
            setName(place.name);
            mapRef.current.panTo({ lat, lng });
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        const newDestination = {
            id: Date.now(),
            name,
            image,
            location,
            members: [],
            comments: [],
        };
        onCreate(newDestination);
    };

    return (
        <form className="create-destination-form" onSubmit={handleSubmit}>
            <h2>Créer une nouvelle destination</h2>

            <label>Image URL</label>
            <input type="text" value={image} onChange={(e) => setImage(e.target.value)} />

            <label>Nom / Lieu</label>
            <PlaceAutocompleteElement
                inputAttributes={{ placeholder: 'Entrez un lieu...' }}
                onPlaceChange={handlePlaceSelect}
            />

            <GoogleMap
                zoom={8}
                center={location}
                mapContainerStyle={{ height: '300px', width: '100%', marginTop: '1rem' }}
                options={{ styles: mapStyles }}
                onLoad={(map) => (mapRef.current = map)}
            >
                <MarkerF position={location} />
            </GoogleMap>

            <button type="submit">Créer</button>
        </form>
    );
}
